        queue = deque()
        queue.append((i, j))
        visited[i][j] = True
        total = grid[i][j]
        while queue:
            x, y = queue.popleft()
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] > 0:
                    visited[nx][ny] = True
                    total += grid[nx][ny]
                    queue.append((nx, ny))
        return total

    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0 and not visited[i][j]:
                island_value = bfs(i, j)
                if island_value % k == 0:
                    count += 1
    return count
